INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00331', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲乙為配偶，未約定財產制。甲乙大吵後，甲於民國111年5月將其婚後財 產價值新臺幣（下同）3,000 萬元 A 屋，以 1,000 萬元出售並移轉所有權於 丙。於111年8月離婚時，甲有婚後存款1,000萬元，乙有婚後財產價值2,000 萬元；A屋價值3,100萬元。關於剩餘財產分配之敘述，下列何者正確？', '["乙如證明甲係為減少乙之分配而出售A屋，雙方婚後剩餘財產差額應為 2,100萬元", "乙如證明甲係為減少乙之分配而出售A屋，丙所受利益為2,100萬元", "乙如證明丙明知甲出售 A屋有損乙之分配，亦得於離婚時聲請撤銷該 行為", "乙如合法撤銷甲丙間 A 屋之買賣及移轉，雙方婚後剩餘財產差額應為 2,000萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00332', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲男乙女婚後生有一子 A。甲乙於民國 105 年間依法出養 A 與未婚之丙 男。108 年 7 月間甲死亡。109 年 5 月間，丙與乙結婚，婚後生一女 B。 110年4月間，乙丙遭意外，乙當場死亡，丙於意外後1個月死亡。下列 何者正確？', '["甲之繼承人為乙、A", "乙之繼承人為丙、A、B", "A應於甲死亡後1年內，以書面向法院表示其為繼承人，逾期視為拋棄 繼承", "丙之繼承人為乙、A、B"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00333', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於遺囑方式之敘述，下列何者錯誤？', '["密封遺囑，如不具備密封遺囑所定之方式，而具備自書遺囑之方式者， 有自書遺囑之效力", "代筆遺囑，由遺囑人指定三人以上之見證人，由遺囑人口述遺囑意旨， 使見證人中之一人筆記、宣讀、講解，經遺囑人認可後，記明年、月、 日及代筆人之姓名，由見證人全體及遺囑人同行簽名，遺囑人不能簽名 者，應按指印代之", "製作公證遺囑時，遺囑人不能簽名者，由公證人將其事由記明，使按指 印代之", "口授筆記遺囑時，須由遺囑人指定二人以上之見證人，並口述遺囑意旨， 由見證人中之一人，將該遺囑意旨，據實作成筆記，並記明年、月、日， 依法應由見證人全體及遺囑人同行簽名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00334', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '民法第 1178 條所定之公示催告期限內，有繼承人承認繼承時，遺產管理 人在繼承人承認繼承前所為之職務上行為，得擬制為何種行為？', '["繼承人之委任", "繼承人之代理", "繼承人之信託", "繼承人之委託"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00335', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'essay', '假設勞動市場為完全競爭，勞動市場反供給函數為：
W =0.5+(L/100) （其中：W 為淨工資率；L為勞動工時）。
n n
又勞動市場反需求函數為：
W =10 （其中：W 為毛工資率）。
g g
在政府對勞動所得課徵稅率為 t（0<t<1）的比例勞動所得稅時，試回
答下列問題：
請列出政府稅收函數（也就是將政府稅收表示成稅率的函數）。
（5 分）
請計算可使政府稅收達到極大的稅率水準。（5 分）
請在縱軸為政府稅收橫軸為稅率的情況下，繪製對應於政府稅收函
數的政府稅收線。（5分）
若目前比例勞動所得稅的稅率為 50%，你建議政府應如何調整稅
率，並具體說明建議進行稅率調整的理由。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00336', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'essay', '請利用無異曲線分析法，在第一種商品為稻米，第二種商品為用來購
買稻米以外其他商品之支出金額，並且完全競爭稻米市場的市場供給
線為水平線的情況下。繪圖分析政府先對稻米從價課徵消費稅，之後
再將稅收全數發還給消費者，在下列不同假設下對於消費者效用的影
響效果：
稻米為劣等財，並且所得效果與替代效果相互抵消。（15分）
稻米為正常財。（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00337', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '下列何者是租稅的特性？①財政收入性  ②強制性  ③政策性  ④個別 報償性', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00338', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '有關租稅歸宿之敘述，下列何者正確？', '["租稅的歸宿分析是探討在價格不變下租稅對效用的影響", "差別租稅歸宿分析（differentialtaxincidenceanalysis）是探討租稅如何影 響總所得在不同所得階層之間的分配問題", "絕對租稅歸宿分析（absolutetaxincidenceanalysis）是探討以新稅替代舊 稅的影響效果", "均衡成長歸宿分析（balancedgrowthincidenceanalysis）是探討不影響資 本累積的租稅組合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00339', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設政府對完全競爭市場的財貨課徵從量稅，下列敘述何者正確？', '["假定需求為完全無彈性，對必需品從量課稅具累進性", "假定需求為完全無彈性，對奢侈品從量課稅具累進性", "假定供給為完全無彈性，對奢侈品從量課稅具累進性", "假定供給為完全無彈性，對必需品從量課稅具累進性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00340', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '政府對儲蓄課徵利息所得稅，其他條件不變時，下列敘述何者正確？', '["短期歸宿使資本存量立即減少", "長期歸宿使資本存量不變", "短期歸宿對勞動需求增加", "長期歸宿使工資下跌"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
